import io
from xhtml2pdf import pisa


class DocumentGenerator:
    def generate_text_pdf(self, text: str) -> bytes:
        html = f'<html><body><pre>{text}</pre></body></html>'
        return self.html_to_pdf(html)

    def html_to_pdf(self, html: str) -> bytes:
        """Convert HTML string to PDF bytes."""
        output = io.BytesIO()
        status = pisa.CreatePDF(io.StringIO(html), dest=output)
        if status.err:
            raise RuntimeError(f'PDF conversion failed with {status.err} errors')
        return output.getvalue()
